## Service Gateway

```hcl
resource "oci_core_service_gateway" "sgw" {
  compartment_id = var.compartment_id
  vcn_id         = oci_core_vcn.vcn.id
  display_name   = "service-gateway"
  services {
    service_id = data.oci_core_services.orcl_services.services[0].id
  }
}
```

### Route Table

```hcl
resource "oci_core_route_table" "service_rt" {
  compartment_id = var.compartment_id
  vcn_id         = oci_core_vcn.vcn.id

  route_rules {
    destination       = "all-oics-in-oracle-services-network"
    destination_type  = "SERVICE_CIDR_BLOCK"
    network_entity_id = oci_core_service_gateway.sgw.id
  }
}
```

### Data Source

```hcl
data "oci_core_services" "orcl_services" {
  filter {
    name   = "name"
    values = ["OCI Streaming"]
  }
}
